            int count = countPrime(nums, idx);
            result.push_back(count);
            k = max(k, count);
        }
        return result;
    }

    int countPrime(vector<int>& nums, int idx) {
        int count = 0;
        for (int i = 0; i < nums.size(); i++) {
            if (isPrime(nums[i]) {
                count++;
            }
        }
        return count;
    }

    bool isPrime(int num) {
